<template>

<div class="container-fluid d-flex flex-column">

  <div class="row row-cols-2">

    <img src="@/assets/costin.jpg" class="col-md-6">

    <div class="col-md-6">

          <h1>Constantin Lungu</h1>

    <p class="greeting"> Hi there! I'm Constantin and I'm a <span class="keyword">Software Engineer</span>. My daily work revolves around <span class="keyword">Data Engineering</span> and <span class="keyword">Business Intelligence</span>, and I'm also a big <span class="keyword">Python</span> fan. Data Science and Civic Tech are also areas I care about.
    Besides tech, I'm interested in history, geography, foreign languages and travel. I'm currently based in <span class="keyword">Bucharest, Romania.</span> <br> <br> Reach out to me at any of the following platforms:
    </p>

    <Social></Social>

    <div class="projects" >
      <p>Some projects outside work I'm involved in:</p>
    <div v-for="project in projects" v-bind:key="project.label">
      <ul class="project-list">
        <li>
          <span class="project-label">
            <a v-bind:href="project.link">{{project.label}}</a>
          </span>

          <span v-if="project.type != 'owner'" class="badge badge-dark">{{project.type}}</span>

          <span class="project-description">{{project.description}}</span>
        </li>
      </ul>
    </div>
    </div>

  </div>
  </div>

</div>
</template>

<script>
import Social from '../components/Social'
import data from '@/data'
export default {
  name: 'Home',
  components: {
    'Social': Social
  },
  data () {
    return {
      projects: data.projects
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>

h1 {
  padding: 20px 0px;
  font-weight: bold;
}

ul {
  list-style-type: none;
  padding: 0;
}
li {
  margin: 0 10px;
}
a {
  color: #42b983;
}

img {
  padding: 0px;
}

.keyword {
  font-weight: bold;
}

.project-list {
  list-style-type: none;
  padding: 10px;
}

.project-list > li {
  display: table-cell;
  text-align: left;
}

.project-label {
  font-weight: bold;
  padding-right: 10px;
}

.project-description {
  padding-left: 10px;
}

.projects, .greeting {
  padding-top: 20px;
  font-size: 1.5em;
  text-align: justify;
}

</style>



